                if (c + 1 < GRID_SIZE && board[r][c+1] == fl) count++;
            }
        }
        return count;
    }

    double calculate_separation_penalty() const {
        // For each flavor, find connected components, then penalize
        // separation between component pairs weighted by their sizes
        double total_penalty = 0.0;

        for (int fl = 1; fl <= NUM_FLAVORS; ++fl) {
            // Find all connected components of this flavor
            std::array<std::array<bool, GRID_SIZE>, GRID_SIZE> visited;
            for (int i = 0; i < GRID_SIZE; ++i) visited[i].fill(false);

            struct CompInfo {
                int size;
                int sum_r, sum_c; // for centroid
            };
            CompInfo comps[34]; // max 33 candies per flavor
            int num_comps = 0;

            std::array<std::pair<int, int>, GRID_SIZE * GRID_SIZE> q_arr;
            // Also store min/max positions for fast distance approximation
            int comp_cells_r[34][34];
            int comp_cells_c[34][34];
            int comp_sizes[34] = {};

            for (int r_start = 0; r_start < GRID_SIZE; ++r_start) {
                for (int c_start = 0; c_start < GRID_SIZE; ++c_start) {
                    if (board[r_start][c_start] == fl && !visited[r_start][c_start]) {
                        int comp_size = 0;
                        int sr = 0, sc = 0;

                        q_arr[0] = {r_start, c_start};
                        visited[r_start][c_start] = true;
                        int head = 0, tail = 1;

                        while (head < tail) {
                            int curr_r = q_arr[head].first;
                            int curr_c = q_arr[head].second;
                            head++;
                            if (comp_size < 34) {
                                comp_cells_r[num_comps][comp_size] = curr_r;
                                comp_cells_c[num_comps][comp_size] = curr_c;
                            }
                            comp_size++;
                            sr += curr_r;
                            sc += curr_c;

                            for (int i = 0; i < NUM_DIRECTIONS; ++i) {
                                int nr = curr_r + DR[i];
                                int nc = curr_c + DC[i];
                                if (nr >= 0 && nr < GRID_SIZE && nc >= 0 && nc < GRID_SIZE &&
                                    !visited[nr][nc] && board[nr][nc] == fl) {
                                    visited[nr][nc] = true;
                                    q_arr[tail++] = {nr, nc};
                                }
                            }
                        }
                        comps[num_comps] = {comp_size, sr, sc};
                        comp_sizes[num_comps] = comp_size;
                        num_comps++;
                    }
                }
            }

            // For each pair of components, compute min Manhattan distance between any two cells
            for (int i = 0; i < num_comps; ++i) {
                for (int j = i + 1; j < num_comps; ++j) {
                    int min_dist = 100;
                    int si = std::min(comp_sizes[i], 34);
                    int sj = std::min(comp_sizes[j], 34);
                    for (int a = 0; a < si; ++a) {
                        for (int b = 0; b < sj; ++b) {
                            int d = std::abs(comp_cells_r[i][a] - comp_cells_r[j][b])
                                  + std::abs(comp_cells_c[i][a] - comp_cells_c[j][b]);
                            if (d < min_dist) min_dist = d;
                        }
                    }
