        std::pair<int, int> candy_loc = current_gs.find_pth_empty_cell(p_val_1_indexed);
        current_gs.place_candy(candy_loc.first, candy_loc.second, G_FLAVOR_SEQUENCE[t_0_indexed]);

        double time_used = elapsed_ms();
        double time_remaining = TOTAL_TIME_BUDGET_MS - time_used;
        int turns_remaining = NUM_TURNS - t_0_indexed;
        double budget_per_turn = time_remaining / turns_remaining;

        // Adaptive parameters based on time budget and game progress
        int samples_d1, samples_d2, max_depth;

        if (t_0_indexed < 20) {
            // Early game: board is sparse, evaluation is fast
            max_depth = 2;
            samples_d1 = 25;
            samples_d2 = 8;
        } else if (t_0_indexed < 50) {
            // Mid game
            max_depth = 2;
            samples_d1 = 20;
            samples_d2 = 6;
        } else if (t_0_indexed < 80) {
            // Late-mid game
            max_depth = 2;
            samples_d1 = 15;
            samples_d2 = 5;
        } else {
            // End game: board is dense, evaluation is expensive
            max_depth = 1;
            samples_d1 = 12;
            samples_d2 = 4;
        }

        // Safety: if we're running low on time, reduce samples
        if (budget_per_turn < 10.0) {
            max_depth = 1;
            samples_d1 = 6;
            samples_d2 = 3;
        } else if (budget_per_turn < 15.0) {
            samples_d1 = std::min(samples_d1, 10);
            samples_d2 = std::min(samples_d2, 4);
            max_depth = std::min(max_depth, 1);
        }

        char chosen_dir_char = decide_tilt_direction_logic(current_gs, samples_d1, samples_d2, max_depth);

        std::cout << chosen_dir_char << std::endl;

