                if (board[r][c] != 0) cnt[board[r][c]]++;
            }
            int max_cnt = *std::max_element(cnt.begin() + 1, cnt.end());
            score += max_cnt * max_cnt;
        }
        for (int c = 0; c < GRID_SIZE; ++c) {
            std::array<int, NUM_FLAVORS + 1> cnt{};
            for (int r = 0; r < GRID_SIZE; ++r) {
                if (board[r][c] != 0) cnt[board[r][c]]++;
            }
            int max_cnt = *std::max_element(cnt.begin() + 1, cnt.end());
            score += max_cnt * max_cnt;
        }
        return score;
    }

    double evaluate() const {
        long long sum_sq_comp = calculate_sum_sq_comp_size();
        int adj_count = count_same_flavor_adjacencies();
        double bb_tight = bounding_box_tightness();
        double rc_purity = row_col_purity();

        double progress = static_cast<double>(turn_num_1_indexed) / NUM_TURNS;

        // Connectivity: the actual objective, increasingly important
        double conn_weight = 25.0 + 75.0 * progress;
        // Adjacency: local proxy
        double adj_weight = 35.0;
        // Bounding box tightness: encourages compaction into small rectangles
        double bb_weight = 3.0 * (1.0 - progress * 0.3);
        // Row/column purity: encourages band-like flavor separation
        double rc_weight = 2.0 * (1.0 - progress * 0.5);

        return conn_weight * sum_sq_comp + adj_weight * adj_count
             + bb_weight * bb_tight + rc_weight * rc_purity;
    }
};

double eval_lookahead(const GameState& state_after_tilt, int turn_T_of_candy_just_processed,
                      int depth_remaining, int samples_d1, int samples_d2);

char decide_tilt_direction_logic(const GameState& current_gs_after_placement,
                                  int samples_d1, int samples_d2, int max_depth) {
    double best_overall_eval = std::numeric_limits<double>::lowest();
    int best_dir_idx = 0;

    int turn_T_for_lookahead_base = current_gs_after_placement.turn_num_1_indexed;

    for (int i = 0; i < NUM_DIRECTIONS; ++i) {
        GameState gs_after_tilt = current_gs_after_placement;
        gs_after_tilt.apply_tilt(i);

        double eval = eval_lookahead(gs_after_tilt, turn_T_for_lookahead_base,
                                     max_depth, samples_d1, samples_d2);

        if (eval > best_overall_eval) {
            best_overall_eval = eval;
            best_dir_idx = i;
        }
    }
    return DIR_CHARS[best_dir_idx];
}


double eval_lookahead(const GameState& state_after_tilt, int turn_T_of_candy_just_processed,
                      int depth_remaining, int samples_d1, int samples_d2) {
    if (depth_remaining == 0 || turn_T_of_candy_just_processed == NUM_TURNS) {
        return state_after_tilt.evaluate();
    }

    int num_empty = state_after_tilt.count_empty_cells();
    if (num_empty == 0) {
        return state_after_tilt.evaluate();
    }

    int next_candy_flavor = G_FLAVOR_SEQUENCE[turn_T_of_candy_just_processed];
    int sample_count = (depth_remaining == 2) ? samples_d1 : samples_d2;
    int actual_num_samples = std::min(sample_count, num_empty);

    if (actual_num_samples == 0) {
        return state_after_tilt.evaluate();
    }

    double sum_over_sampled_placements = 0.0;
    for (int s = 0; s < actual_num_samples; ++s) {
        int p_val_1_indexed_sample;
        if (actual_num_samples == num_empty) {
            p_val_1_indexed_sample = s + 1;
        } else {
            p_val_1_indexed_sample = rng.uniform_int(1, num_empty);
        }

        GameState S_after_placement = state_after_tilt;
        std::pair<int, int> candy_loc = S_after_placement.find_pth_empty_cell(p_val_1_indexed_sample);
        S_after_placement.place_candy(candy_loc.first, candy_loc.second, next_candy_flavor);
        S_after_placement.turn_num_1_indexed = turn_T_of_candy_just_processed + 1;

        double max_eval_for_this_placement = std::numeric_limits<double>::lowest();
        for (int dir_idx_next_tilt = 0; dir_idx_next_tilt < NUM_DIRECTIONS; ++dir_idx_next_tilt) {
            GameState S_after_next_tilt = S_after_placement;
            S_after_next_tilt.apply_tilt(dir_idx_next_tilt);
            double val = eval_lookahead(S_after_next_tilt, S_after_placement.turn_num_1_indexed,
                                        depth_remaining - 1, samples_d1, samples_d2);
            if (val > max_eval_for_this_placement) {
                max_eval_for_this_placement = val;
            }
        }
        sum_over_sampled_placements += max_eval_for_this_placement;
    }

    return sum_over_sampled_placements / actual_num_samples;
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    program_start_time = std::chrono::steady_clock::now();

    for (int t = 0; t < NUM_TURNS; ++t) {
        std::cin >> G_FLAVOR_SEQUENCE[t];
    }

    GameState current_gs;

    const double TOTAL_TIME_BUDGET_MS = 1900.0;

    for (int t_0_indexed = 0; t_0_indexed < NUM_TURNS; ++t_0_indexed) {
        current_gs.turn_num_1_indexed = t_0_indexed + 1;

        int p_val_1_indexed;
        std::cin >> p_val_1_indexed;

        std::pair<int, int> candy_loc = current_gs.find_pth_empty_cell(p_val_1_indexed);
        current_gs.place_candy(candy_loc.first, candy_loc.second, G_FLAVOR_SEQUENCE[t_0_indexed]);

        double time_used = elapsed_ms();
        double time_remaining = TOTAL_TIME_BUDGET_MS - time_used;
        int turns_remaining = NUM_TURNS - t_0_indexed;
        double budget_per_turn = time_remaining / turns_remaining;

        int samples_d1, samples_d2, max_depth;

        if (t_0_indexed < 20) {
            max_depth = 2;
            samples_d1 = 22;
            samples_d2 = 7;
        } else if (t_0_indexed < 50) {
            max_depth = 2;
            samples_d1 = 18;
            samples_d2 = 6;
        } else if (t_0_indexed < 80) {
            max_depth = 2;
            samples_d1 = 14;
            samples_d2 = 5;
        } else {
            max_depth = 1;
            samples_d1 = 10;
            samples_d2 = 4;
        }

        if (budget_per_turn < 8.0) {
            max_depth = 1;
            samples_d1 = 5;
            samples_d2 = 3;
        } else if (budget_per_turn < 14.0) {
            samples_d1 = std::min(samples_d1, 8);
            samples_d2 = std::min(samples_d2, 3);
            max_depth = 1;
        }

        char chosen_dir_char = decide_tilt_direction_logic(current_gs, samples_d1, samples_d2, max_depth);

        std::cout << chosen_dir_char << std::endl;

        int dir_idx_to_apply = 0;
        for(int k=0; k<NUM_DIRECTIONS; ++k) {
            if(DIR_CHARS[k] == chosen_dir_char) {
                dir_idx_to_apply = k;
                break;
            }
        }
        current_gs.apply_tilt(dir_idx_to_apply);
    }

    return 0;
}
